using System;
using System.ComponentModel.Composition;
using XrmToolBox.Extensibility;
using XrmToolBox.Extensibility.Interfaces;

namespace DataverseProcessMapper
{
    /// <summary>
    /// Factory discovered by XrmToolBox via MEF. The metadata drives the tile
    /// shown on the XrmToolBox home screen.
    /// </summary>
    [Export(typeof(IXrmToolBoxPlugin))]
    [ExportMetadata("Name", "Dataverse Process Mapper")]
    [ExportMetadata("Description", "List Classic Workflows and Power Automate flows and render visual process maps, exportable to PDF or HTML.")]
    [ExportMetadata("BackgroundColor", "White")]
    [ExportMetadata("PrimaryFontColor", "Black")]
    [ExportMetadata("SecondaryFontColor", "DarkGray")]
    [ExportMetadata("SmallImageBase64", SmallIconBase64)]
    [ExportMetadata("BigImageBase64", BigIconBase64)]
    public class ProcessMapperPlugin : PluginBase, IGitHubPlugin
    {

        private const string SmallIconBase64 = ""; // 32x32
        private const string BigIconBase64 = "";   // 120x120

        public override IXrmToolBoxPluginControl GetControl()
        {
            return new ProcessMapperControl();
        }

        // IGitHubPlugin — surfaces an "Update" / help link in XrmToolBox.
        public string RepositoryName => "DataverseProcessMapper";
        public string UserName => "your-github-user";
    }
}
